mapper.insert:
INSERT INTO plant (
    plantno, memberno, growth_level, is_active, last_used_time, points
) VALUES (
    plant_seq.nextval, #{memberno}, #{growth_level}, #{is_active}, SYSTIMESTAMP, #{points}
)

mapper.select:
SELECT plantno, memberno, growth_level, is_active, last_used_time, points
FROM plant
WHERE memberno = #{memberno}

mapper.update:
UPDATE plant
SET growth_level = growth_level + 5
WHERE plantno = #{plantno}

mapper.select:
SELECT plantno, memberno, growth_level, is_active, last_used_time, points
FROM plant
WHERE memberno = #{memberno}
